import { NgModule } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Routes } from '@angular/router';

import { BQGComponent } from './bqg/bqg.component';
import { CRYComponent } from './cry/cry.component';
import { LOCComponent } from './loc/loc.component';
import { MUPComponent } from './mup/mup.component';
import { POFComponent } from './pof/pof.component';
import { REGComponent } from './reg/reg.component';



const routes: Routes = [{
  path: 'bqg',
  component: BQGComponent
}, {
  path: 'cry',
  component: CRYComponent
}, {
  path: 'loc',
  component: LOCComponent
}, {
  path: 'mup',
  component: MUPComponent
}, {
  path: 'pof',
  component: POFComponent
}, {
  path: 'reg',
  component: REGComponent
}];

@NgModule({
  declarations: [],
  imports: [
    CommonModule,
    RouterModule.forChild(routes)
  ],
  exports: [RouterModule]
})
export class GEORoutingModule { }
